 1	import * as React from 'react';
 2	import { CREATE_SS_PAGE_URL, FLASH_STORAGE_CLASS } from '@odf/core/constants';
 3	import { StartingPoint } from '@odf/core/types/install-ui';
 4	import { useCustomTranslation } from '@odf/shared';
 5	import { GreenCheckCircleIcon } from '@openshift-console/dynamic-plugin-sdk';
 6	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 7	import { Trans } from 'react-i18next';
 8	import { useNavigate } from 'react-router-dom-v5-compat';
 9	import {
10	  EmptyState,
11	  EmptyStateActions,
12	  EmptyStateBody,
13	  EmptyStateFooter,
14	  EmptyStateHeader,
15	  EmptyStateIcon,
16	  EmptyStateVariant,
17	  Modal,
18	  Button,
19	  ButtonVariant,
20	  ModalVariant,
21	} from '@patternfly/react-core';
22	
23	export const DeployDataFoundationModal: ModalComponent = ({ closeModal }) => {
24	  const { t } = useCustomTranslation();
25	  const navigate = useNavigate();
26	
27	  const onDeploy = () => {
28	    const urlParams = new URLSearchParams({
29	      mode: StartingPoint.STORAGE_CLUSTER,
30	      storageClass: FLASH_STORAGE_CLASS,
31	    });
32	    navigate(`${CREATE_SS_PAGE_URL}?${urlParams.toString()}`);
33	    closeModal();
34	  };
35	
36	  return (
37	    <Modal
38	      title={t('Deploy Data Foundation')}
39	      isOpen={true}
40	      onClose={closeModal}
41	      variant={ModalVariant.small}
42	    >
43	      <EmptyState variant={EmptyStateVariant.sm}>
44	        <EmptyStateHeader
45	          titleText={t('Deploy Data Foundation on IBM FlashSystem')}
46	          headingLevel="h4"
47	          icon={<EmptyStateIcon icon={GreenCheckCircleIcon} />}
48	        />
49	        <EmptyStateBody>
50	          <Trans t={t}>
51	            Your IBM FlashSystem has been successfully configured. To enable
52	            persistent storage for your OpenShift workloads, deploy Data
53	            Foundation using the available FlashSystem storage class. Click
54	            Deploy Data Foundation to begin installation and configure storage
55	            resources using IBM FlashSystem.
56	          </Trans>
57	        </EmptyStateBody>
58	        <EmptyStateFooter>
59	          <EmptyStateActions>
60	            <Button variant={ButtonVariant.primary} onClick={onDeploy}>
61	              {t('Deploy Data Foundation')}
62	            </Button>
63	          </EmptyStateActions>
64	        </EmptyStateFooter>
65	      </EmptyState>
66	    </Modal>
67	  );
68	};

